import React, { useState } from 'react';
import { Icon, openModal, closeModal } from '@capital/component';
import {
  showErrorToasts,
  showToasts,
  ChatInputActionContextProps,
} from '@capital/common';
import { MUSIC_SOURCES, MusicSource, Song } from '../const';
import { searchMusic } from '../api/musicApi';
import { buildAlbumCardContent, buildArtistCardContent, buildSongCardContent } from '../utils/share';

const ShareModal: React.FC<{ actions: ChatInputActionContextProps }> = ({ actions }) => {
  const [source, setSource] = useState<MusicSource>('netease');
  const [keyword, setKeyword] = useState('');
  const [results, setResults] = useState<Song[]>([]);
  const [loading, setLoading] = useState(false);

  const doSearch = async () => {
    if (!keyword.trim()) return;
    setLoading(true);
    try {
      setResults(await searchMusic(keyword.trim(), source, 20));
    } catch (e) {
      showErrorToasts(e);
    } finally {
      setLoading(false);
    }
  };

  const share = (content: string) => {
    actions.sendMsg(content);
    showToasts('已分享到当前会话', 'success');
    closeModal();
  };

  return (
    <div style={{ width: 380, maxWidth: '80vw', padding: 16 }}>
      <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 10 }}>分享音乐到聊天</div>
      <div style={{ display: 'flex', gap: 8, marginBottom: 10 }}>
        <select
          value={source}
          onChange={(e) => setSource(e.target.value as MusicSource)}
          style={{ padding: '6px 8px', borderRadius: 6 }}
        >
          {MUSIC_SOURCES.map((s) => (
            <option key={s.value} value={s.value}>
              {s.label}
            </option>
          ))}
        </select>
        <input
          autoFocus
          value={keyword}
          onChange={(e) => setKeyword(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && doSearch()}
          placeholder="搜索歌曲/歌手/专辑"
          style={{ flex: 1, padding: '6px 10px', borderRadius: 6, border: '1px solid rgba(120,120,120,0.3)' }}
        />
        <div
          onClick={doSearch}
          style={{ padding: '0 12px', display: 'flex', alignItems: 'center', background: '#22c55e', color: '#fff', borderRadius: 6, cursor: 'pointer' }}
        >
          <Icon icon="mdi:magnify" width={16} />
        </div>
      </div>

      <div style={{ maxHeight: 320, overflowY: 'auto' }}>
        {loading && <div style={{ textAlign: 'center', opacity: 0.6 }}>搜索中...</div>}
        {results.map((song, i) => (
          <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '6px 2px' }}>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 13, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{song.name}</div>
              <div style={{ fontSize: 11, opacity: 0.6, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{song.artist}</div>
            </div>
            <div style={{ display: 'flex', gap: 8 }}>
              <Icon icon="mdi:send" width={16} style={{ cursor: 'pointer' }} title="分享歌曲" onClick={() => share(buildSongCardContent(song))} />
              <Icon icon="mdi:album" width={16} style={{ cursor: 'pointer' }} title="分享专辑" onClick={() => share(buildAlbumCardContent(song))} />
              <Icon icon="mdi:account-music" width={16} style={{ cursor: 'pointer' }} title="分享歌手" onClick={() => share(buildArtistCardContent(song))} />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

/**
 * 聊天输入框 "+" 菜单中的分享音乐入口
 */
export function openMusicShareModal(actions: ChatInputActionContextProps) {
  openModal(<ShareModal actions={actions} />, { closable: true, maskClosable: true });
}
